<?php
namespace WCSA\Providers\Sms; defined('ABSPATH') || exit; use WCSA\Options; use WCSA\Support\Helpers; use WCSA\Support\Logger;
final class KavenegarSmsProvider implements SmsProviderInterface{ public function id():string{return 'kavenegar';} public function title():string{return 'کاوه‌نگار';} public function sendOtp(string $m,string $code,array $ctx=[]):bool{ $api=trim((string)Options::get('kavenegar_api_key','')); if(!$api){Logger::add('error','Kavenegar API key is empty'); return false;} $mobile=Helpers::mobileNational($m); $pattern=trim((string)Options::get('kavenegar_pattern','')); if($pattern){$url='https://api.kavenegar.com/v1/'.rawurlencode($api).'/verify/lookup.json';$body=['receptor'=>$mobile,'token'=>$code,'template'=>$pattern];}else{$url='https://api.kavenegar.com/v1/'.rawurlencode($api).'/sms/send.json';$msg=str_replace(['{code}','{site}'],[$code,get_bloginfo('name')],(string)Options::get('sms_message_template','کد ورود شما: {code}'));$body=['receptor'=>$mobile,'message'=>$msg];$sender=trim((string)Options::get('kavenegar_sender',''));if($sender)$body['sender']=$sender;} $r=wp_remote_post($url,['timeout'=>10,'redirection'=>0,'headers'=>['Content-Type'=>'application/x-www-form-urlencoded; charset=UTF-8'],'body'=>$body]); if(is_wp_error($r)){Logger::add('error','Kavenegar network error',['mobile'=>$m]);return false;} $j=json_decode(wp_remote_retrieve_body($r),true); $ok=(int)wp_remote_retrieve_response_code($r)>=200&&(int)wp_remote_retrieve_response_code($r)<300&&is_array($j)&&isset($j['return']['status'])&&(int)$j['return']['status']===200; Logger::add($ok?'info':'error',$ok?'OTP sent':'Kavenegar rejected',['mobile'=>$m]); return $ok;}}
